// src/components/Header.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// SVG avatar icon
const AvatarIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" id="avatar-man-profile-person-human-boy" width="42" height="42" viewBox="0 0 16 16">
    {/* … seu SVG … */}
  </svg>
);

export default function Header() {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  // Extract only first name
  const fullName = user?.nome || user?.usuario || '';
  const firstName = fullName.split(' ')[0] || 'Usuário';

  const toggleDropdown = () => setDropdownOpen(o => !o);
  const handlePerfil = () => {
    setDropdownOpen(false);
    navigate('/perfil');
  };
  const handleLogout = () => {
    setDropdownOpen(false);
    logout();
    navigate('/login', { replace: true });
  };

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-white shadow flex items-center justify-between px-6 z-50">
      <h1 className="text-xl font-bold text-[#3172C0]">PoliUB Atendimentos</h1>

      <div className="relative flex items-center space-x-2">
        {/* Always show avatar + first name in black */}
        <AvatarIcon />
        <span className="text-black font-medium">{firstName}</span>

        {/* Dropdown trigger */}
        <button
          onClick={toggleDropdown}
          className="ml-2 rounded-full focus:outline-none focus:ring-2 focus:ring-blue-400"
        >
          ▼
        </button>

        {dropdownOpen && (
          <ul className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg">
            <li className="px-4 py-2 text-black font-medium border-b border-gray-100">
              {firstName}
            </li>
            <li>
              <button
                onClick={handlePerfil}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-black"
              >
                Meu Perfil
              </button>
            </li>
            <li>
              <button
                onClick={handleLogout}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-red-600"
              >
                Sair
              </button>
            </li>
          </ul>
        )}
      </div>
    </header>
  );
}
